using System;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System.Data.SqlClient;
using System.Text;
using System.Linq;
using System.Security.Cryptography;

public static class SecureAzureFunction
{
    private static readonly string[] SensitiveHeaders = new[] 
    { 
        "authorization", 
        "cookie", 
        "x-api-key", 
        "x-auth-token",
        "api-key",
        "apikey"
    };

    private static readonly string[] SensitiveFields = new[]
    {
        "password",
        "token",
        "secret",
        "apikey",
        "api_key",
        "creditcard",
        "ssn",
        "authorization"
    };

    [FunctionName("SecureFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        string correlationId = Guid.NewGuid().ToString();
        
        try
        {
            log.LogInformation($"[{correlationId}] Function execution started");

            LogRequestHeaders(req, log, correlationId);
            
            string requestBody = await new StreamReader(req.Body).ReadToEndAsync();
            LogRequestBody(requestBody, log, correlationId);

            string userId = ExtractUserId(req);
            log.LogInformation($"[{correlationId}] Processing request for user: {MaskSensitiveData(userId)}");

            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var result = await ExecuteDatabaseQuery(connectionString, userId, log, correlationId);

            log.LogInformation($"[{correlationId}] Function execution completed successfully");
            
            return new OkObjectResult(new { 
                correlationId = correlationId,
                result = result,
                timestamp = DateTime.UtcNow
            });
        }
        catch (Exception ex)
        {
            LogException(ex, log, correlationId);
            
            return new ObjectResult(new { 
                error = "An error occurred processing your request",
                correlationId = correlationId,
                timestamp = DateTime.UtcNow
            })
            {
                StatusCode = 500
            };
        }
    }

    private static void LogRequestHeaders(HttpRequest req, ILogger log, string correlationId)
    {
        log.LogInformation($"[{correlationId}] Request Headers:");
        
        foreach (var header in req.Headers)
        {
            string headerValue = header.Value.ToString();
            
            if (SensitiveHeaders.Contains(header.Key.ToLower()))
            {
                headerValue = MaskSensitiveData(headerValue);
            }
            
            log.LogInformation($"[{correlationId}] {header.Key}: {headerValue}");
        }
        
        log.LogInformation($"[{correlationId}] Request Method: {req.Method}");
        log.LogInformation($"[{correlationId}] Request Path: {req.Path}");
        log.LogInformation($"[{correlationId}] Request Query: {MaskQueryString(req.QueryString.ToString())}");
        log.LogInformation($"[{correlationId}] Client IP: {req.HttpContext.Connection.RemoteIpAddress}");
    }

    private static void LogRequestBody(string body, ILogger log, string correlationId)
    {
        if (string.IsNullOrEmpty(body))
        {
            log.LogInformation($"[{correlationId}] Request Body: (empty)");
            return;
        }

        string sanitizedBody = MaskSensitiveDataInJson(body);
        
        if (sanitizedBody.Length > 10000)
        {
            sanitizedBody = sanitizedBody.Substring(0, 10000) + "... (truncated)";
        }
        
        log.LogInformation($"[{correlationId}] Request Body: {sanitizedBody}");
    }

    private static async Task<string> ExecuteDatabaseQuery(string connectionString, string userId, ILogger log, string correlationId)
    {
        string maskedUserId = MaskSensitiveData(userId);
        
        log.LogInformation($"[{correlationId}] Executing database query for user: {maskedUserId}");
        
        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            log.LogInformation($"[{correlationId}] Database connection established");

            string query = "SELECT Id, Name, Email FROM Users WHERE UserId = @UserId";
            log.LogInformation($"[{correlationId}] Query: {query}");
            log.LogInformation($"[{correlationId}] Parameters: @UserId = {maskedUserId}");

            using (SqlCommand command = new SqlCommand(query, connection))
            {
                command.Parameters.AddWithValue("@UserId", userId);
                
                using (SqlDataReader reader = await command.ExecuteReaderAsync())
                {
                    StringBuilder result = new StringBuilder();
                    
                    while (await reader.ReadAsync())
                    {
                        string id = reader["Id"].ToString();
                        string name = reader["Name"].ToString();
                        string email = reader["Email"].ToString();
                        
                        log.LogInformation($"[{correlationId}] Query result - Id: {id}, Name: {MaskSensitiveData(name)}, Email: {MaskEmail(email)}");
                        
                        result.AppendLine($"Id: {id}, Name: {name}, Email: {email}");
                    }
                    
                    log.LogInformation($"[{correlationId}] Query executed successfully");
                    return result.ToString();
                }
            }
        }
    }

    private static void LogException(Exception ex, ILogger log, string correlationId)
    {
        log.LogError($"[{correlationId}] Exception Type: {ex.GetType().FullName}");
        log.LogError($"[{correlationId}] Exception Message: {ex.Message}");
        log.LogError($"[{correlationId}] Stack Trace: {ex.StackTrace}");
        
        if (ex.InnerException != null)
        {
            log.LogError($"[{correlationId}] Inner Exception Type: {ex.InnerException.GetType().FullName}");
            log.LogError($"[{correlationId}] Inner Exception Message: {ex.InnerException.Message}");
            log.LogError($"[{correlationId}] Inner Exception Stack Trace: {ex.InnerException.StackTrace}");
        }

        if (ex is SqlException sqlEx)
        {
            log.LogError($"[{correlationId}] SQL Error Number: {sqlEx.Number}");
            log.LogError($"[{correlationId}] SQL Error State: {sqlEx.State}");
            log.LogError($"[{correlationId}] SQL Server: {MaskSensitiveData(sqlEx.Server)}");
        }

        log.LogError($"[{correlationId}] Exception Data:");
        foreach (var key in ex.Data.Keys)
        {
            log.LogError($"[{correlationId}] {key}: {MaskSensitiveData(ex.Data[key]?.ToString())}");
        }
    }

    private static string ExtractUserId(HttpRequest req)
    {
        if (req.Headers.TryGetValue("X-User-Id", out var userId))
        {
            return userId.ToString();
        }
        
        if (req.Query.TryGetValue("userId", out var queryUserId))
        {
            return queryUserId.ToString();
        }
        
        return "anonymous";
    }

    private static string MaskSensitiveData(string data)
    {
        if (string.IsNullOrEmpty(data))
        {
            return data;
        }

        if (data.Length <= 4)
        {
            return new string('*', data.Length);
        }

        return data.Substring(0, 2) + new string('*', data.Length - 4) + data.Substring(data.Length - 2);
    }

    private static string MaskEmail(string email)
    {
        if (string.IsNullOrEmpty(email) || !email.Contains("@"))
        {
            return MaskSensitiveData(email);
        }

        var parts = email.Split('@');
        return MaskSensitiveData(parts[0]) + "@" + parts[1];
    }

    private static string MaskQueryString(string queryString)
    {
        if (string.IsNullOrEmpty(queryString))
        {
            return queryString;
        }

        foreach (var sensitiveField in SensitiveFields)
        {
            var pattern = $"{sensitiveField}=";
            var index = queryString.IndexOf(pattern, StringComparison.OrdinalIgnoreCase);
            
            if (index >= 0)
            {
                var startIndex = index + pattern.Length;
                var endIndex = queryString.IndexOf('&', startIndex);
                
                if (endIndex == -1)
                {
                    endIndex = queryString.Length;
                }
                
                var valueLength = endIndex - startIndex;
                var maskedValue = new string('*', Math.Min(valueLength, 10));
                queryString = queryString.Substring(0, startIndex) + maskedValue + 
                             (endIndex < queryString.Length ? queryString.Substring(endIndex) : "");
            }
        }
        
        return queryString;
    }

    private static string MaskSensitiveDataInJson(string json)
    {
        if (string.IsNullOrEmpty(json))
        {
            return json;
        }

        string result = json;
        
        foreach (var field in SensitiveFields)
        {
            var patterns = new[]
            {
                $"\"{field}\"\\s*:\\s*\"([^\"]+)\"",
                $"'{field}'\\s*:\\s*'([^']+)'",
                $"\"{field}\"\\s*:\\s*([^,}}\\s]+)"
            };

            foreach (var pattern in patterns)
            {
                result = System.Text.RegularExpressions.Regex.Replace(
                    result,
                    pattern,
                    match => match.Value.Replace(match.Groups[1].Value, "***REDACTED***"),
                    System.Text.RegularExpressions.RegexOptions.IgnoreCase
                );
            }
        }
        
        return result;
    }
